import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.*;

public class SecureCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String name = reader.readLine();

        // Properly sanitize and encode user input before displaying it
        try {
            String encodedName = ESAPI.encoder().encodeForHTML(name);
            System.out.println("Hello, " + encodedName + "!");
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
        }
    }
}

